import React, { useState } from 'react';

const Contact = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: ''
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitMessage, setSubmitMessage] = useState('');

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setTimeout(() => {
      setSubmitMessage('Thank you for your message! We will get back to you within 24 hours.');
      setFormData({ name: '', email: '', subject: '', message: '' });
      setIsSubmitting(false);
    }, 1500);
  };

  const supportChannels = [
    { icon: '📧', title: 'Email Support', detail: 'support@ridefleet.com', sub: 'Response within 24 hours' },
    { icon: '📞', title: 'Phone Support', detail: '+91 9876543210', sub: 'Mon-Fri, 8AM - 8PM' },
    { icon: '💬', title: 'Live Chat', detail: 'Available on Dashboard', sub: 'Real-time assistance' },
  ];

  const locations = [
    { name: 'Main Store — City Center', address: '123 Bike Street, City Center, Bangalore 560001', phone: '+91 9876543210' },
    { name: 'Airport Branch', address: 'Airport Road, Near Terminal 1, Bangalore 560017', phone: '+91 9876543211' },
    { name: 'Railway Station Branch', address: 'Station Road, Opp Platform 1, Bangalore 560023', phone: '+91 9876543212' },
  ];

  return (
    <div>
      <div className="section-title">
        <h2>Support Center</h2>
        <p>Get in touch with our team for any assistance or inquiries</p>
      </div>

      {/* Support Channels */}
      <div className="stats-grid" style={{ marginBottom: '1.75rem' }}>
        {supportChannels.map((channel, i) => (
          <div className="card" key={i} style={{ cursor: 'pointer' }}>
            <div className="card-body" style={{ textAlign: 'center', padding: '1.5rem' }}>
              <div style={{ fontSize: '2rem', marginBottom: '0.75rem' }}>{channel.icon}</div>
              <div style={{ fontWeight: 700, fontSize: '0.95rem', color: 'var(--text-primary)', marginBottom: '0.25rem' }}>{channel.title}</div>
              <div style={{ fontWeight: 600, fontSize: '0.9rem', color: 'var(--primary)', marginBottom: '0.25rem' }}>{channel.detail}</div>
              <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{channel.sub}</div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid-2">
        {/* Contact Form */}
        <div className="card">
          <div className="card-header">
            <h3>Send a Message</h3>
          </div>
          <div className="card-body">
            {submitMessage && (
              <div className="form-success-msg">{submitMessage}</div>
            )}

            <form onSubmit={handleSubmit}>
              <div className="form-row">
                <div className="form-group">
                  <label className="form-label">Your Name *</label>
                  <input type="text" name="name" className="form-control" value={formData.name} onChange={handleInputChange} required placeholder="Enter your full name" />
                </div>
                <div className="form-group">
                  <label className="form-label">Your Email *</label>
                  <input type="email" name="email" className="form-control" value={formData.email} onChange={handleInputChange} required placeholder="Enter your email" />
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Subject *</label>
                <input type="text" name="subject" className="form-control" value={formData.subject} onChange={handleInputChange} required placeholder="Brief description of your inquiry" />
              </div>

              <div className="form-group">
                <label className="form-label">Message *</label>
                <textarea name="message" className="form-control" rows="5" value={formData.message} onChange={handleInputChange} required placeholder="Describe your issue or question in detail..." />
              </div>

              <button type="submit" className="btn btn-primary btn-block" disabled={isSubmitting}>
                {isSubmitting ? 'Sending...' : 'Send Message'}
              </button>
            </form>
          </div>
        </div>

        {/* Locations & Emergency */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
          <div className="card">
            <div className="card-header">
              <h3>Our Locations</h3>
            </div>
            <div className="card-body">
              {locations.map((loc, i) => (
                <div key={i} style={{
                  padding: '0.85rem 0',
                  borderBottom: i < locations.length - 1 ? '1px solid var(--border-light)' : 'none'
                }}>
                  <div style={{ fontWeight: 600, fontSize: '0.9rem', color: 'var(--text-primary)', marginBottom: '0.25rem' }}>{loc.name}</div>
                  <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '0.25rem' }}>{loc.address}</div>
                  <div style={{ fontSize: '0.8rem', color: 'var(--primary)', fontWeight: 500 }}>📞 {loc.phone}</div>
                </div>
              ))}
            </div>
          </div>

          <div className="card">
            <div className="card-header">
              <h3>Business Hours</h3>
            </div>
            <div className="card-body">
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', borderBottom: '1px solid var(--border-light)' }}>
                <span style={{ fontSize: '0.85rem', fontWeight: 500 }}>Monday — Friday</span>
                <span style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>8:00 AM — 8:00 PM</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0', borderBottom: '1px solid var(--border-light)' }}>
                <span style={{ fontSize: '0.85rem', fontWeight: 500 }}>Saturday</span>
                <span style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>9:00 AM — 6:00 PM</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0' }}>
                <span style={{ fontSize: '0.85rem', fontWeight: 500 }}>Sunday</span>
                <span style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>9:00 AM — 4:00 PM</span>
              </div>
            </div>
          </div>

          <div className="alert alert--danger">
            <h4>🚨 Emergency Support</h4>
            <p>For roadside assistance or emergencies during your rental:</p>
            <div style={{ fontSize: '1.1rem', fontWeight: 700, marginTop: '0.5rem' }}>📞 +91 9876543219 (24/7)</div>
          </div>
        </div>
      </div>
    </div>
  );
